import React, { useState, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, Pagination, SectionTitle } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, Folder, ChevronDown, ChevronRight, Phone, Mail, User } from 'lucide-react';
import { MOCK_DEPTS } from '../constants';
import { Department } from '../types';

const ITEMS_PER_PAGE = 10;

export const DeptManager: React.FC = () => {
  const [data, setData] = useState<Department[]>(MOCK_DEPTS);
  const [currentPage, setCurrentPage] = useState(1);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [expandedKeys, setExpandedKeys] = useState<Set<string>>(new Set(['1', '11', '12']));

  // Search State
  const [searchName, setSearchName] = useState('');
  const [searchStatus, setSearchStatus] = useState('');

  // Edit/Add State
  const [currentDept, setCurrentDept] = useState<Partial<Department>>({});

  // Confirm Dialog State
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'inactive' } | null>(null);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  // Helper to flatten data for table with indentation
  const flattenDepts = (depts: Department[], depth = 0): (Department & { depth: number })[] => {
    let result: (Department & { depth: number })[] = [];
    depts.forEach(d => {
      // Filter logic applies here if needed, but usually tree filtering is complex. 
      // For simplicity, we filter on the flat list or keep parents if children match.
      // Here we will just flatten and then filter the visible list based on expansion.
      result.push({ ...d, depth });
      if (d.children && expandedKeys.has(d.id)) {
        result = result.concat(flattenDepts(d.children, depth + 1));
      }
    });
    return result;
  };

  // Helper to get all nodes for parent selection
  const getAllNodes = (depts: Department[]): Department[] => {
      let res: Department[] = [];
      depts.forEach(d => {
          res.push(d);
          if (d.children) res = res.concat(getAllNodes(d.children));
      });
      return res;
  };

  const flatData = useMemo(() => {
      // 1. Flatten visible
      const visibleNodes = flattenDepts(data);

      // 2. Filter
      return visibleNodes.filter(d => {
          const matchName = !searchName || d.name.toLowerCase().includes(searchName.toLowerCase());
          const matchStatus = !searchStatus || d.status === searchStatus;
          return matchName && matchStatus;
      });
  }, [data, expandedKeys, searchName, searchStatus]);

  const toggleExpand = (id: string) => {
      const newSet = new Set(expandedKeys);
      if (newSet.has(id)) newSet.delete(id);
      else newSet.add(id);
      setExpandedKeys(newSet);
  };

  const handleAdd = (parentId: string | null = null) => {
      setCurrentDept({
          parentId,
          status: 'active',
          sort: 1
      });
      setIsModalOpen(true);
  };

  const handleEdit = (dept: Department) => {
      setCurrentDept({ ...dept });
      setIsModalOpen(true);
  };

  const handleSave = () => {
      if (!currentDept.name || !currentDept.leader) {
          alert("请完善基本信息");
          return;
      }

      const deptToSave = { ...currentDept } as Department;

      if (currentDept.id) {
          // Update Recursive
          const updateNode = (nodes: Department[]): Department[] => {
              return nodes.map(n => {
                  if (n.id === currentDept.id) {
                      return { ...n, ...deptToSave, children: n.children }; // Preserve children
                  }
                  if (n.children) {
                      return { ...n, children: updateNode(n.children) };
                  }
                  return n;
              });
          };
          setData(updateNode(data));
      } else {
          // Create
          const newDept = {
              ...deptToSave,
              id: Date.now().toString(),
              createTime: new Date().toLocaleDateString(),
              children: []
          };

          if (newDept.parentId) {
              const addNode = (nodes: Department[]): Department[] => {
                  return nodes.map(n => {
                      if (n.id === newDept.parentId) {
                          return { ...n, children: [...(n.children || []), newDept] };
                      }
                      if (n.children) {
                          return { ...n, children: addNode(n.children) };
                      }
                      return n;
                  });
              };
              setData(addNode(data));
              // Auto expand parent
              setExpandedKeys(new Set([...expandedKeys, newDept.parentId]));
          } else {
              setData([...data, newDept]);
          }
      }
      setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          const removeNode = (nodes: Department[]): Department[] => {
              return nodes.filter(n => n.id !== deleteTargetId).map(n => ({
                  ...n,
                  children: n.children ? removeNode(n.children) : undefined
              }));
          };
          setData(removeNode(data));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  const initiateStatusChange = (dept: Department, checked: boolean) => {
      setTargetStatusChange({ id: dept.id, newStatus: checked ? 'active' : 'inactive' });
      setConfirmOpen(true);
  };

  const confirmStatusChange = () => {
      if (targetStatusChange) {
          const updateStatus = (nodes: Department[]): Department[] => {
              return nodes.map(n => {
                  if (n.id === targetStatusChange.id) {
                      return { ...n, status: targetStatusChange.newStatus };
                  }
                  if (n.children) {
                      return { ...n, children: updateStatus(n.children) };
                  }
                  return n;
              });
          };
          setData(updateStatus(data));
      }
      setConfirmOpen(false);
      setTargetStatusChange(null);
  };

  const columns = [
      {
          header: '部门名称',
          accessor: (row: any) => (
              <div style={{ paddingLeft: `${row.depth * 24}px` }} className="flex items-center">
                  {row.children && row.children.length > 0 ? (
                      <button onClick={() => toggleExpand(row.id)} className="mr-2 text-slate-400 hover:text-white">
                          {expandedKeys.has(row.id) ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                      </button>
                  ) : <span className="w-[22px]"></span>}
                  <Folder size={16} className="mr-2 text-blue-500" />
                  <span className="text-slate-200 font-medium">{row.name}</span>
              </div>
          ),
          width: '30%'
      },
      { header: '负责人', accessor: 'leader', width: '15%' },
      { header: '联系电话', accessor: 'phone', width: '15%' },
      { header: '排序', accessor: 'sort', width: '10%' },
      {
          header: '状态',
          accessor: (row: Department) => (
              <Switch 
                  checked={row.status === 'active'} 
                  onChange={(c) => initiateStatusChange(row, c)} 
              />
          ),
          width: '10%'
      },
      { header: '创建时间', accessor: 'createTime' },
      {
          header: '操作',
          accessor: (row: Department) => (
              <div className="flex space-x-2">
                  <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row)}>编辑</Button>
                  <Button size="sm" variant="ghost" className="!text-green-500 hover:!text-green-400" icon={<Plus size={14} />} onClick={() => handleAdd(row.id)}>新增下级</Button>
                  <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.id)}>删除</Button>
              </div>
          ),
          width: '250px'
      }
  ];

  return (
      <div className="h-full flex flex-col space-y-4">
          <Card className="shrink-0">
              <div className="flex justify-between items-end">
                  <div className="flex gap-4 items-end">
                      <Input 
                          label="部门名称"
                          placeholder="请输入部门名称"
                          className="w-48"
                          value={searchName}
                          onChange={e => setSearchName(e.target.value)}
                      />
                      <Select 
                          label="状态"
                          options={[{label: '全部', value: ''}, {label: '正常', value: 'active'}, {label: '停用', value: 'inactive'}]}
                          value={searchStatus}
                          onChange={e => setSearchStatus(e.target.value)}
                          className="w-32"
                      />
                      <div className="flex gap-2 pb-0.5">
                          <Button icon={<Search size={16}/>}>查询</Button>
                          <Button variant="secondary" icon={<RotateCcw size={16}/>} onClick={() => { setSearchName(''); setSearchStatus(''); }}>重置</Button>
                      </div>
                  </div>
                  <Button variant="primary" className="bg-blue-600 hover:bg-blue-500" icon={<Plus size={16}/>} onClick={() => handleAdd()}>新增部门</Button>
              </div>
          </Card>

          <Card className="flex-1 overflow-hidden flex flex-col" title="部门列表">
              <div className="flex-1 overflow-auto">
                  <Table columns={columns} data={flatData} keyField="id" />
              </div>
          </Card>

          <Modal
              isOpen={isModalOpen}
              onClose={() => setIsModalOpen(false)}
              title={currentDept.id ? "编辑部门" : "新增部门"}
              size="md"
              footer={
                  <>
                      <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
                      <Button onClick={handleSave}>确定</Button>
                  </>
              }
          >
              <div className="space-y-6">
                  <SectionTitle title="部门信息" />
                  <div className="space-y-4">
                      <div className="relative">
                          <label className="text-sm text-slate-400 block mb-1.5">上级部门</label>
                          <select 
                              className="w-full px-3 py-2 bg-[#1e293b] border border-slate-700 rounded focus:ring-1 focus:ring-blue-500 focus:border-blue-500 text-white appearance-none hover:border-slate-600"
                              value={currentDept.parentId || ''}
                              onChange={e => setCurrentDept({...currentDept, parentId: e.target.value || null})}
                          >
                              <option value="">顶级部门</option>
                              {getAllNodes(data).map(d => (
                                  <option key={d.id} value={d.id} disabled={d.id === currentDept.id}>{d.name}</option>
                              ))}
                          </select>
                          <ChevronDown size={14} className="absolute right-3 top-[38px] pointer-events-none text-slate-500" />
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                          <Input 
                              label="部门名称"
                              placeholder="请输入"
                              value={currentDept.name || ''}
                              onChange={e => setCurrentDept({...currentDept, name: e.target.value})}
                          />
                          <Input 
                              label="显示排序"
                              type="number"
                              value={currentDept.sort || 0}
                              onChange={e => setCurrentDept({...currentDept, sort: parseInt(e.target.value)})}
                          />
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                          <Input 
                              label="负责人"
                              placeholder="负责人姓名"
                              value={currentDept.leader || ''}
                              onChange={e => setCurrentDept({...currentDept, leader: e.target.value})}
                              prefix={<User size={14}/>}
                          />
                          <Input 
                              label="联系电话"
                              placeholder="手机号码"
                              value={currentDept.phone || ''}
                              onChange={e => setCurrentDept({...currentDept, phone: e.target.value})}
                              prefix={<Phone size={14}/>}
                          />
                      </div>

                      <Input 
                          label="邮箱"
                          placeholder="部门邮箱"
                          value={currentDept.email || ''}
                          onChange={e => setCurrentDept({...currentDept, email: e.target.value})}
                          prefix={<Mail size={14}/>}
                      />

                      <div className="flex flex-col gap-2">
                          <label className="text-sm text-slate-400">部门状态</label>
                          <div className="flex items-center gap-2">
                              <Switch 
                                  checked={currentDept.status === 'active'}
                                  onChange={c => setCurrentDept({...currentDept, status: c ? 'active' : 'inactive'})}
                              />
                              <span className="text-sm text-slate-300">{currentDept.status === 'active' ? '正常' : '停用'}</span>
                          </div>
                      </div>
                  </div>
              </div>
          </Modal>

          <ConfirmDialog 
              isOpen={confirmOpen} 
              message={`确定要${targetStatusChange?.newStatus === 'active' ? '启用' : '停用'}该部门吗？`}
              onConfirm={confirmStatusChange}
              onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
          />

          <ConfirmDialog 
              isOpen={deleteConfirmOpen} 
              title="删除部门"
              message="确定要删除该部门吗？如果有下级部门将一并删除。"
              onConfirm={confirmDelete}
              onCancel={() => { setDeleteConfirmOpen(false); setDeleteTargetId(null); }}
          />
      </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { DomainManager } from './pages/DomainManager';
import { MenuManager } from './pages/MenuManager';
import { RoleManager } from './pages/RoleManager';
import { UserManager } from './pages/UserManager';
import { DeptManager } from './pages/DeptManager';
import { ComponentManager } from './pages/ComponentManager';
import { TemplateManager } from './pages/TemplateManager';
import { DemoMode } from './pages/DemoMode';
import { Shield, Settings, Users, Network, Menu as MenuIcon, LogOut, ChevronDown, User as UserIcon, LayoutGrid, ArrowRightLeft, Check, Search, Layout, Monitor, FolderTree } from 'lucide-react';
import { GlobalContext, ViewMode } from './GlobalContext';
import { MOCK_DOMAINS } from './constants';
import { Domain } from './types';

// --- Navigation Config ---
const NAV_ITEMS = [
  { 
    id: 'system', 
    title: '系统管理', 
    icon: Settings,
    children: [
        { id: 'domain', title: '域管理', icon: Network },
        { id: 'menu', title: '菜单管理', icon: MenuIcon },
        { id: 'dept', title: '部门管理', icon: FolderTree },
        { id: 'role', title: '角色管理', icon: Shield },
        { id: 'user', title: '用户管理', icon: Users },
    ]
  },
  {
    id: 'config',
    title: '配置管理',
    icon: Layout,
    children: [
      { id: 'component', title: '组件管理', icon: LayoutGrid },
      { id: 'template', title: '模板管理', icon: Layout },
    ]
  }
];

const App: React.FC = () => {
  const [activePage, setActivePage] = useState('domain'); 
  const [isNavOpen, setIsNavOpen] = useState(false);

  // --- Global Context State ---
  const [mode, setMode] = useState<ViewMode>('fusion');
  const [currentDomain, setCurrentDomain] = useState<Domain | null>(null);

  // --- Mode Switcher State ---
  const [isSwitcherOpen, setIsSwitcherOpen] = useState(false);
  const switcherRef = useRef<HTMLDivElement>(null);
  const [switcherTab, setSwitcherTab] = useState<'fusion' | 'switching'>('fusion');

  // Close switcher when clicking outside
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (switcherRef.current && !switcherRef.current.contains(event.target as Node)) {
        setIsSwitcherOpen(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const getCurrentPageTitle = () => {
    for (const item of NAV_ITEMS) {
      if (item.children) {
        const child = item.children.find(c => c.id === activePage);
        if (child) return { parent: item.title, child: child.title };
      }
    }
    return { parent: '', child: '' };
  };

  const breadcrumbs = getCurrentPageTitle();

  const renderContent = () => {
    switch (activePage) {
      case 'domain': return <DomainManager />;
      case 'menu': return <MenuManager />;
      case 'dept': return <DeptManager />;
      case 'role': return <RoleManager />;
      case 'user': return <UserManager />;
      case 'component': return <ComponentManager />;
      case 'template': return <TemplateManager />;
      default: return <DomainManager />;
    }
  };

  const handleSwitchToFusion = () => {
      setMode('fusion');
      setCurrentDomain(null);
      setIsSwitcherOpen(false);
  };

  const handleSwitchToDomain = (domain: Domain) => {
      setMode('switching');
      setCurrentDomain(domain);
      setIsSwitcherOpen(false);
  };

  return (
    <GlobalContext.Provider value={{ mode, currentDomain, setMode, setCurrentDomain }}>
    <div className="flex flex-col h-screen bg-[#020617] text-slate-200 font-sans overflow-hidden">

      {/* Top Header Navigation */}
      <header className="h-16 bg-[#0f172a] border-b border-slate-800 flex items-center justify-between px-6 shrink-0 z-50 shadow-md">
         <div className="flex items-center space-x-8">
            <div className="flex items-center cursor-pointer" onClick={() => setActivePage('domain')}>
                <Shield className="text-blue-500 mr-2" size={24} />
                <span className="font-bold text-lg tracking-wide text-white">政企业务智慧运维管家</span>
            </div>

            <nav className="hidden md:flex items-center space-x-1">
                {NAV_ITEMS.map(item => (
                    <div key={item.id} className="relative group">
                        <button 
                            className={`flex items-center px-3 py-2 rounded-md text-sm font-medium transition-colors ${breadcrumbs.parent === item.title ? 'text-white bg-slate-800' : 'text-slate-400 hover:text-white hover:bg-slate-800/50'}`}
                        >
                            <item.icon size={16} className="mr-2" />
                            {item.title}
                            <ChevronDown size={14} className="ml-1 opacity-70" />
                        </button>

                        <div className="absolute left-0 mt-1 w-48 bg-[#0f172a] border border-slate-700 rounded-md shadow-lg py-1 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-50">
                            {item.children && item.children.map(child => (
                                <button
                                    key={child.id}
                                    onClick={() => { setActivePage(child.id); }}
                                    className={`w-full flex items-center px-4 py-2 text-sm text-left hover:bg-slate-800 ${activePage === child.id ? 'text-blue-400 bg-slate-800/50' : 'text-slate-300'}`}
                                >
                                    <child.icon size={14} className="mr-2" />
                                    {child.title}
                                </button>
                            ))}
                        </div>
                    </div>
                ))}
            </nav>
         </div>

         <div className="flex items-center space-x-4">
            <div className="relative" ref={switcherRef}>
                <button 
                    onClick={() => { setIsSwitcherOpen(!isSwitcherOpen); setSwitcherTab(mode); }}
                    className={`flex items-center space-x-2 px-3 py-1.5 rounded-full border transition-all ${mode === 'fusion' ? 'bg-blue-900/30 border-blue-500/50 text-blue-200 hover:bg-blue-900/50' : 'bg-green-900/30 border-green-500/50 text-green-200 hover:bg-green-900/50'}`}
                >
                    {mode === 'fusion' ? <LayoutGrid size={14} /> : <ArrowRightLeft size={14} />}
                    <span className="text-xs font-medium">
                        {mode === 'fusion' ? '全域融合模式' : `域: ${currentDomain?.name || '未知'}`}
                    </span>
                    <ChevronDown size={12} className={`transition-transform ${isSwitcherOpen ? 'rotate-180' : ''}`} />
                </button>

                {isSwitcherOpen && (
                    <div className="absolute right-0 mt-2 w-80 bg-[#1e293b] border border-slate-700 rounded-lg shadow-2xl z-[100] overflow-hidden">
                        <div className="flex border-b border-slate-700">
                            <button 
                                onClick={() => setSwitcherTab('fusion')}
                                className={`flex-1 py-3 text-xs font-bold text-center transition-colors ${switcherTab === 'fusion' ? 'bg-blue-600/10 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-slate-200 hover:bg-slate-800'}`}
                            >
                                跨域融合 (Fusion)
                            </button>
                            <button 
                                onClick={() => setSwitcherTab('switching')}
                                className={`flex-1 py-3 text-xs font-bold text-center transition-colors ${switcherTab === 'switching' ? 'bg-green-600/10 text-green-400 border-b-2 border-green-500' : 'text-slate-400 hover:text-slate-200 hover:bg-slate-800'}`}
                            >
                                域切换 (Switching)
                            </button>
                        </div>

                        <div className="p-4 max-h-[400px] overflow-y-auto custom-scrollbar bg-[#0f172a]">
                            {switcherTab === 'fusion' ? (
                                <div className="space-y-4">
                                    <div className="p-3 bg-blue-900/20 border border-blue-800 rounded text-blue-200 text-xs leading-relaxed">
                                        全局数据聚合：当前可查看所有域的组件与模板资源。
                                    </div>
                                    <button 
                                        onClick={handleSwitchToFusion}
                                        className="w-full py-2 bg-blue-600 hover:bg-blue-500 text-white rounded text-sm font-medium transition-colors flex items-center justify-center gap-2"
                                    >
                                        {mode === 'fusion' && <Check size={16} />}
                                        启用融合模式
                                    </button>
                                </div>
                            ) : (
                                <div className="space-y-3">
                                    {MOCK_DOMAINS.filter(d => !d.isSuper).map(domain => (
                                        <button
                                            key={domain.id}
                                            onClick={() => handleSwitchToDomain(domain)}
                                            className={`w-full flex items-center justify-between p-3 rounded border text-left transition-all ${
                                                mode === 'switching' && currentDomain?.id === domain.id
                                                ? 'bg-green-900/20 border-green-500/50 text-green-300'
                                                : 'bg-slate-800 border-slate-700 text-slate-300 hover:border-slate-500 hover:bg-slate-700'
                                            }`}
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className={`w-8 h-8 rounded-full flex items-center justify-center ${mode === 'switching' && currentDomain?.id === domain.id ? 'bg-green-900/40 text-green-400' : 'bg-slate-700 text-slate-400'}`}>
                                                    <Users size={14} />
                                                </div>
                                                <div className="truncate text-sm font-bold">{domain.name}</div>
                                            </div>
                                            {mode === 'switching' && currentDomain?.id === domain.id && <Check size={16} className="text-green-500" />}
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                )}
            </div>

            <div className="flex items-center space-x-3 pl-4 border-l border-slate-700">
                <div className="flex flex-col items-end">
                    <span className="text-sm font-medium text-white">{mode === 'fusion' ? '超级管理员' : (currentDomain?.manager)}</span>
                    <span className="text-[10px] text-slate-500">{mode === 'fusion' ? '省中心' : '项目域'}</span>
                </div>
                <div className="w-9 h-9 rounded-full bg-slate-800 border border-slate-600 flex items-center justify-center">
                    <UserIcon size={18} className="text-slate-300" />
                </div>
                <button className="text-slate-400 hover:text-red-400 transition-colors">
                    <LogOut size={18} />
                </button>
            </div>
         </div>
      </header>

      <main className="flex-1 overflow-hidden bg-[#020617] flex flex-col p-6">
        <div className="mb-4 flex items-center justify-between">
             <div className="flex items-center text-sm text-slate-400">
                <span>{breadcrumbs.parent}</span>
                <span className="mx-2 text-slate-600">/</span>
                <span className="text-blue-400 font-medium">{breadcrumbs.child}</span>
             </div>
             {mode === 'switching' && currentDomain && (
                 <div className="flex items-center px-3 py-1 bg-blue-900/20 border border-blue-500/30 rounded text-[10px] text-blue-400">
                    <Network size={12} className="mr-1"/> 
                    业务类型限制生效中
                 </div>
             )}
        </div>
        <div className="flex-1 overflow-hidden">
            {renderContent()}
        </div>
      </main>
    </div>
    </GlobalContext.Provider>
  );
};

