import React, { useState, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, Pagination, SectionTitle } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, Briefcase } from 'lucide-react';
import { MOCK_POSTS } from '../constants';
import { Post } from '../types';

const ITEMS_PER_PAGE = 10;

export const PostManager: React.FC = () => {
  const [data, setData] = useState<Post[]>(MOCK_POSTS);
  const [currentPage, setCurrentPage] = useState(1);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentPost, setCurrentPost] = useState<Partial<Post>>({});

  // Search State
  const [searchName, setSearchName] = useState('');
  const [searchCode, setSearchCode] = useState('');
  const [searchStatus, setSearchStatus] = useState('');

  // Confirm Dialogs
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  const filteredData = useMemo(() => {
      return data.filter(p => {
          const matchName = !searchName || p.name.toLowerCase().includes(searchName.toLowerCase());
          const matchCode = !searchCode || p.code.toLowerCase().includes(searchCode.toLowerCase());
          const matchStatus = !searchStatus || p.status === searchStatus;
          return matchName && matchCode && matchStatus;
      });
  }, [data, searchName, searchCode, searchStatus]);

  const paginatedData = filteredData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);
  const totalPages = Math.ceil(filteredData.length / ITEMS_PER_PAGE);

  const handleEdit = (post: Post) => {
      setCurrentPost({ ...post });
      setIsModalOpen(true);
  };

  const handleAdd = () => {
      setCurrentPost({ status: 'active', sort: 0 });
      setIsModalOpen(true);
  };

  const handleSave = () => {
      if (!currentPost.name || !currentPost.code) {
          alert("请完善岗位信息");
          return;
      }
      if (currentPost.id) {
          setData(data.map(p => p.id === currentPost.id ? { ...p, ...currentPost } as Post : p));
      } else {
          const newPost = {
              ...currentPost,
              id: Date.now().toString(),
              createTime: new Date().toLocaleDateString()
          } as Post;
          setData([...data, newPost]);
      }
      setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          setData(data.filter(p => p.id !== deleteTargetId));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  const columns = [
      { header: '岗位编码', accessor: 'code' },
      { header: '岗位名称', accessor: 'name' },
      { header: '显示顺序', accessor: 'sort' },
      { 
          header: '状态', 
          accessor: (row: Post) => (
              <Badge color={row.status === 'active' ? 'blue' : 'red'}>
                  {row.status === 'active' ? '正常' : '停用'}
              </Badge>
          ) 
      },
      { header: '创建时间', accessor: 'createTime' },
      {
          header: '操作',
          accessor: (row: Post) => (
              <div className="flex space-x-2">
                  <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14}/>} onClick={() => handleEdit(row)}>编辑</Button>
                  <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14}/>} onClick={() => handleDelete(row.id)}>删除</Button>
              </div>
          )
      }
  ];

  return (
      <div className="h-full flex flex-col space-y-4">
          <Card className="shrink-0">
              <div className="flex justify-between items-end">
                  <div className="flex gap-4 items-end">
                      <Input 
                          label="岗位名称" 
                          placeholder="请输入岗位名称" 
                          value={searchName} 
                          onChange={e => setSearchName(e.target.value)}
                          className="w-40"
                      />
                      <Input 
                          label="岗位编码" 
                          placeholder="请输入岗位编码" 
                          value={searchCode} 
                          onChange={e => setSearchCode(e.target.value)}
                          className="w-40"
                      />
                      <Select 
                          label="状态"
                          options={[{label: '全部', value: ''}, {label: '正常', value: 'active'}, {label: '停用', value: 'inactive'}]}
                          value={searchStatus}
                          onChange={e => setSearchStatus(e.target.value)}
                          className="w-32"
                      />
                      <div className="flex gap-2 pb-0.5">
                          <Button icon={<Search size={16}/>}>查询</Button>
                          <Button variant="secondary" icon={<RotateCcw size={16}/>} onClick={() => { setSearchName(''); setSearchCode(''); setSearchStatus(''); }}>重置</Button>
                      </div>
                  </div>
                  <Button variant="primary" className="bg-green-600 hover:bg-green-500" icon={<Plus size={16}/>} onClick={handleAdd}>新增岗位</Button>
              </div>
          </Card>

          <Card className="flex-1 overflow-hidden flex flex-col" title="岗位列表">
              <div className="flex-1 overflow-auto">
                  <Table columns={columns} data={paginatedData} keyField="id" />
              </div>
              <div className="py-2 border-t border-slate-700 flex justify-between items-center">
                  <div className="text-sm text-slate-400">共 {filteredData.length} 条</div>
                  <Pagination currentPage={currentPage} totalPages={totalPages} onPageChange={setCurrentPage} />
              </div>
          </Card>

          <Modal
              isOpen={isModalOpen}
              onClose={() => setIsModalOpen(false)}
              title={currentPost.id ? "编辑岗位" : "新增岗位"}
              size="md"
              footer={
                  <>
                      <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
                      <Button onClick={handleSave}>确定</Button>
                  </>
              }
          >
              <div className="space-y-4">
                  <Input 
                      label="岗位名称" 
                      value={currentPost.name || ''} 
                      onChange={e => setCurrentPost({...currentPost, name: e.target.value})}
                      placeholder="请输入岗位名称"
                  />
                  <Input 
                      label="岗位编码" 
                      value={currentPost.code || ''} 
                      onChange={e => setCurrentPost({...currentPost, code: e.target.value})}
                      placeholder="请输入编码"
                  />
                  <Input 
                      label="显示顺序" 
                      type="number"
                      value={currentPost.sort || 0} 
                      onChange={e => setCurrentPost({...currentPost, sort: parseInt(e.target.value)})}
                  />
                  <div className="flex flex-col gap-2">
                      <label className="text-sm text-slate-400">岗位状态</label>
                      <div className="flex items-center gap-2">
                          <Switch 
                              checked={currentPost.status === 'active'}
                              onChange={c => setCurrentPost({...currentPost, status: c ? 'active' : 'inactive'})}
                          />
                          <span className="text-sm text-slate-300">{currentPost.status === 'active' ? '正常' : '停用'}</span>
                      </div>
                  </div>
                  <Input 
                      label="备注" 
                      value={currentPost.remark || ''} 
                      onChange={e => setCurrentPost({...currentPost, remark: e.target.value})}
                      placeholder="请输入备注"
                  />
              </div>
          </Modal>

          <ConfirmDialog 
              isOpen={deleteConfirmOpen} 
              title="删除岗位"
              message="确定要删除该岗位吗？"
              onConfirm={confirmDelete}
              onCancel={() => setDeleteConfirmOpen(false)}
          />
      </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, Pagination, SectionTitle } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, Book, List, RefreshCcw } from 'lucide-react';
import { MOCK_DICT_TYPES, MOCK_DICT_DATA } from '../constants';
import { DictType, DictData } from '../types';

export const DictManager: React.FC = () => {
  // Left: Type List State
  const [types, setTypes] = useState<DictType[]>(MOCK_DICT_TYPES);
  const [selectedTypeId, setSelectedTypeId] = useState<string>(MOCK_DICT_TYPES[0]?.id || '');
  const [searchType, setSearchType] = useState('');

  // Right: Data List State
  const [datas, setDatas] = useState<DictData[]>(MOCK_DICT_DATA);
  const [searchLabel, setSearchLabel] = useState('');

  // Modal State
  const [typeModalOpen, setTypeModalOpen] = useState(false);
  const [dataModalOpen, setDataModalOpen] = useState(false);
  const [currentType, setCurrentType] = useState<Partial<DictType>>({});
  const [currentData, setCurrentData] = useState<Partial<DictData>>({});

  // --- Type Logic ---
  const filteredTypes = useMemo(() => {
      return types.filter(t => !searchType || t.name.includes(searchType) || t.type.includes(searchType));
  }, [types, searchType]);

  const handleAddType = () => {
      setCurrentType({ status: 'active' });
      setTypeModalOpen(true);
  };

  const handleEditType = (t: DictType) => {
      setCurrentType({ ...t });
      setTypeModalOpen(true);
  };

  const handleSaveType = () => {
      if (!currentType.name || !currentType.type) return;
      if (currentType.id) {
          setTypes(types.map(t => t.id === currentType.id ? { ...t, ...currentType } as DictType : t));
      } else {
          setTypes([...types, { ...currentType, id: Date.now().toString(), createTime: new Date().toLocaleDateString() } as DictType]);
      }
      setTypeModalOpen(false);
  };

  // --- Data Logic ---
  const selectedTypeObj = types.find(t => t.id === selectedTypeId);

  const filteredDatas = useMemo(() => {
      if (!selectedTypeObj) return [];
      return datas.filter(d => 
          d.dictType === selectedTypeObj.type && 
          (!searchLabel || d.label.includes(searchLabel))
      );
  }, [datas, selectedTypeObj, searchLabel]);

  const handleAddData = () => {
      if (!selectedTypeObj) return;
      setCurrentData({ dictType: selectedTypeObj.type, status: 'active', sort: 0, isDefault: false, classType: 'default' });
      setDataModalOpen(true);
  };

  const handleEditData = (d: DictData) => {
      setCurrentData({ ...d });
      setDataModalOpen(true);
  };

  const handleSaveData = () => {
      if (!currentData.label || !currentData.value) return;
      if (currentData.id) {
          setDatas(datas.map(d => d.id === currentData.id ? { ...d, ...currentData } as DictData : d));
      } else {
          setDatas([...datas, { ...currentData, id: Date.now().toString() } as DictData]);
      }
      setDataModalOpen(false);
  };

  // --- Render ---
  const typeColumns = [
      { header: '字典名称', accessor: 'name' },
      { header: '字典类型', accessor: 'type' },
      { header: '操作', accessor: (row: DictType) => (
          <div className="flex gap-2">
              <button className="text-blue-400 hover:text-blue-300" onClick={(e) => { e.stopPropagation(); handleEditType(row); }}><Edit2 size={12}/></button>
          </div>
      )}
  ];

  const dataColumns = [
      { header: '标签', accessor: 'label' },
      { header: '键值', accessor: 'value' },
      { header: '排序', accessor: 'sort' },
      { 
          header: '样式', 
          accessor: (row: DictData) => (
              <Badge color={row.classType === 'danger' ? 'red' : row.classType === 'success' ? 'green' : row.classType === 'warning' ? 'yellow' : 'blue'}>
                  {row.classType || 'default'}
              </Badge>
          ) 
      },
      { 
          header: '状态', 
          accessor: (row: DictData) => <span className={row.status==='active'?'text-green-400':'text-red-400'}>{row.status==='active'?'正常':'停用'}</span> 
      },
      {
          header: '操作',
          accessor: (row: DictData) => (
              <div className="flex gap-2">
                  <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={12}/>} onClick={() => handleEditData(row)}>编辑</Button>
                  <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={12}/>} onClick={() => setDatas(datas.filter(d => d.id !== row.id))}>删除</Button>
              </div>
          )
      }
  ];

  return (
      <div className="h-full flex gap-4">
          {/* Left: Types */}
          <Card className="w-1/3 flex flex-col" title="字典类型">
              <div className="flex gap-2 mb-3">
                  <Input placeholder="字典名称/类型" value={searchType} onChange={e => setSearchType(e.target.value)} className="flex-1 text-xs h-8" />
                  <Button size="sm" icon={<Plus size={14}/>} onClick={handleAddType}></Button>
              </div>
              <div className="flex-1 overflow-auto border border-slate-700/50 rounded">
                  <table className="w-full text-sm text-left text-slate-300">
                      <thead className="bg-slate-800 text-xs text-slate-400">
                          <tr>
                              <th className="px-3 py-2">名称</th>
                              <th className="px-3 py-2">类型</th>
                              <th className="px-3 py-2 w-10"></th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-800">
                          {filteredTypes.map(t => (
                              <tr 
                                key={t.id} 
                                className={`cursor-pointer hover:bg-slate-800/50 transition-colors ${selectedTypeId === t.id ? 'bg-blue-900/20' : ''}`}
                                onClick={() => setSelectedTypeId(t.id)}
                              >
                                  <td className="px-3 py-2">{t.name}</td>
                                  <td className="px-3 py-2 text-slate-500 text-xs" title={t.type}>{t.type}</td>
                                  <td className="px-3 py-2">
                                      <Edit2 size={12} className="text-slate-500 hover:text-blue-400" onClick={(e) => {e.stopPropagation(); handleEditType(t)}}/>
                                  </td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
              </div>
          </Card>

          {/* Right: Data */}
          <div className="flex-1 flex flex-col gap-4">
              <Card className="shrink-0">
                  <div className="flex justify-between items-center">
                      <div className="flex gap-4 items-center">
                          <span className="text-sm font-bold text-slate-200 flex items-center gap-2">
                              <Book size={16} className="text-blue-500"/>
                              {selectedTypeObj ? selectedTypeObj.name : '请选择字典'}
                          </span>
                          <span className="text-xs text-slate-500 bg-slate-800 px-2 py-0.5 rounded">{selectedTypeObj?.type}</span>
                      </div>
                      <div className="flex gap-2">
                          <Input placeholder="数据标签" value={searchLabel} onChange={e => setSearchLabel(e.target.value)} className="w-40 h-8 text-xs" />
                          <Button size="sm" icon={<Search size={14}/>}>搜索</Button>
                          <Button size="sm" variant="primary" className="bg-green-600 hover:bg-green-500" icon={<Plus size={14}/>} onClick={handleAddData} disabled={!selectedTypeId}>新增数据</Button>
                      </div>
                  </div>
              </Card>

              <Card className="flex-1 overflow-hidden flex flex-col">
                  <div className="flex-1 overflow-auto">
                      <Table columns={dataColumns} data={filteredDatas} keyField="id" />
                  </div>
              </Card>
          </div>

          {/* Modals */}
          <Modal isOpen={typeModalOpen} onClose={() => setTypeModalOpen(false)} title={currentType.id ? "编辑字典类型" : "新增字典类型"} size="sm" 
            footer={<><Button variant="secondary" onClick={() => setTypeModalOpen(false)}>取消</Button><Button onClick={handleSaveType}>确定</Button></>}>
              <div className="space-y-4">
                  <Input label="字典名称" value={currentType.name || ''} onChange={e => setCurrentType({...currentType, name: e.target.value})} />
                  <Input label="字典类型" value={currentType.type || ''} onChange={e => setCurrentType({...currentType, type: e.target.value})} />
                  <Input label="备注" value={currentType.remark || ''} onChange={e => setCurrentType({...currentType, remark: e.target.value})} />
              </div>
          </Modal>

          <Modal isOpen={dataModalOpen} onClose={() => setDataModalOpen(false)} title={currentData.id ? "编辑字典数据" : "新增字典数据"} size="sm"
            footer={<><Button variant="secondary" onClick={() => setDataModalOpen(false)}>取消</Button><Button onClick={handleSaveData}>确定</Button></>}>
              <div className="space-y-4">
                  <Input label="数据标签" value={currentData.label || ''} onChange={e => setCurrentData({...currentData, label: e.target.value})} />
                  <Input label="数据键值" value={currentData.value || ''} onChange={e => setCurrentData({...currentData, value: e.target.value})} />
                  <Input label="显示排序" type="number" value={currentData.sort || 0} onChange={e => setCurrentData({...currentData, sort: parseInt(e.target.value)})} />
                  <Select label="回显样式" options={[{label:'Default',value:'default'},{label:'Primary',value:'primary'},{label:'Success',value:'success'},{label:'Danger',value:'danger'}]} 
                      value={currentData.classType} onChange={e => setCurrentData({...currentData, classType: e.target.value as any})} />
                  <div className="flex flex-col gap-2">
                      <label className="text-sm text-slate-400">状态</label>
                      <Switch checked={currentData.status === 'active'} onChange={c => setCurrentData({...currentData, status: c?'active':'inactive'})} />
                  </div>
              </div>
          </Modal>
      </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Pagination, SectionTitle } from '../components/UI';
import { Search, RotateCcw, FileText, Clock, AlertCircle, Eye } from 'lucide-react';
import { MOCK_LOGS } from '../constants';
import { OperLog } from '../types';

const ITEMS_PER_PAGE = 10;

export const LogManager: React.FC = () => {
  const [logs, setLogs] = useState<OperLog[]>(MOCK_LOGS);
  const [currentPage, setCurrentPage] = useState(1);
  const [searchModule, setSearchModule] = useState('');
  const [searchUser, setSearchUser] = useState('');
  const [searchStatus, setSearchStatus] = useState('');
