import React, { useState, useRef, useEffect } from 'react';
import { DomainManager } from './pages/DomainManager';
import { MenuManager } from './pages/MenuManager';
import { RoleManager } from './pages/RoleManager';
import { UserManager } from './pages/UserManager';
import { DeptManager } from './pages/DeptManager';
import { ComponentManager } from './pages/ComponentManager';
import { TemplateManager } from './pages/TemplateManager';
import { DemoMode } from './pages/DemoMode';
import { Shield, Settings, Users, Network, Menu as MenuIcon, LogOut, ChevronDown, User as UserIcon, LayoutGrid, ArrowRightLeft, Check, Search, Layout, Monitor, FolderTree } from 'lucide-react';
import { GlobalContext, ViewMode } from './GlobalContext';
import { MOCK_DOMAINS } from './constants';
import { Domain } from './types';

// --- Navigation Config ---
const NAV_ITEMS = [
  { 
    id: 'system', 
    title: '系统管理', 
    icon: Settings,
    children: [
        { id: 'domain', title: '域管理', icon: Network },
        { id: 'menu', title: '菜单管理', icon: MenuIcon },
        { id: 'dept', title: '部门管理', icon: FolderTree },
        { id: 'role', title: '角色管理', icon: Shield },
        { id: 'user', title: '用户管理', icon: Users },
    ]
  },
  {
    id: 'config',
    title: '配置管理',
    icon: Layout,
    children: [
      { id: 'component', title: '组件管理', icon: LayoutGrid },
      { id: 'template', title: '模板管理', icon: Layout },
    ]
  }
];

const App: React.FC = () => {
  const [activePage, setActivePage] = useState('domain'); 
  const [isNavOpen, setIsNavOpen] = useState(false);

  // --- Global Context State ---
  const [mode, setMode] = useState<ViewMode>('fusion');
  const [currentDomain, setCurrentDomain] = useState<Domain | null>(null);

  // --- Mode Switcher State ---
  const [isSwitcherOpen, setIsSwitcherOpen] = useState(false);
  const switcherRef = useRef<HTMLDivElement>(null);
  const [switcherTab, setSwitcherTab] = useState<'fusion' | 'switching'>('fusion');

  // Close switcher when clicking outside
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (switcherRef.current && !switcherRef.current.contains(event.target as Node)) {
        setIsSwitcherOpen(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const getCurrentPageTitle = () => {
    for (const item of NAV_ITEMS) {
      if (item.children) {
        const child = item.children.find(c => c.id === activePage);
        if (child) return { parent: item.title, child: child.title };
      }
    }
    return { parent: '', child: '' };
  };

  const breadcrumbs = getCurrentPageTitle();

  const renderContent = () => {
    switch (activePage) {
      case 'domain': return <DomainManager />;
      case 'menu': return <MenuManager />;
      case 'dept': return <DeptManager />;
      case 'role': return <RoleManager />;
      case 'user': return <UserManager />;
      case 'component': return <ComponentManager />;
      case 'template': return <TemplateManager />;
      default: return <DomainManager />;
    }
  };

  const handleSwitchToFusion = () => {
      setMode('fusion');
      setCurrentDomain(null);
      setIsSwitcherOpen(false);
  };

  const handleSwitchToDomain = (domain: Domain) => {
      setMode('switching');
      setCurrentDomain(domain);
      setIsSwitcherOpen(false);
  };

  return (
    <GlobalContext.Provider value={{ mode, currentDomain, setMode, setCurrentDomain }}>
    <div className="flex flex-col h-screen bg-[#020617] text-slate-200 font-sans overflow-hidden">

      {/* Top Header Navigation */}
      <header className="h-16 bg-[#0f172a] border-b border-slate-800 flex items-center justify-between px-6 shrink-0 z-50 shadow-md">
         <div className="flex items-center space-x-8">
            <div className="flex items-center cursor-pointer" onClick={() => setActivePage('domain')}>
                <Shield className="text-blue-500 mr-2" size={24} />
                <span className="font-bold text-lg tracking-wide text-white">政企业务智慧运维管家</span>
            </div>

            <nav className="hidden md:flex items-center space-x-1">
                {NAV_ITEMS.map(item => (
                    <div key={item.id} className="relative group">
                        <button 
                            className={`flex items-center px-3 py-2 rounded-md text-sm font-medium transition-colors ${breadcrumbs.parent === item.title ? 'text-white bg-slate-800' : 'text-slate-400 hover:text-white hover:bg-slate-800/50'}`}
                        >
                            <item.icon size={16} className="mr-2" />
                            {item.title}
                            <ChevronDown size={14} className="ml-1 opacity-70" />
                        </button>

                        <div className="absolute left-0 mt-1 w-48 bg-[#0f172a] border border-slate-700 rounded-md shadow-lg py-1 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-50">
                            {item.children && item.children.map(child => (
                                <button
                                    key={child.id}
                                    onClick={() => { setActivePage(child.id); }}
                                    className={`w-full flex items-center px-4 py-2 text-sm text-left hover:bg-slate-800 ${activePage === child.id ? 'text-blue-400 bg-slate-800/50' : 'text-slate-300'}`}
                                >
                                    <child.icon size={14} className="mr-2" />
                                    {child.title}
                                </button>
                            ))}
                        </div>
                    </div>
                ))}
            </nav>
         </div>

         <div className="flex items-center space-x-4">
            <div className="relative" ref={switcherRef}>
                <button 
                    onClick={() => { setIsSwitcherOpen(!isSwitcherOpen); setSwitcherTab(mode); }}
                    className={`flex items-center space-x-2 px-3 py-1.5 rounded-full border transition-all ${mode === 'fusion' ? 'bg-blue-900/30 border-blue-500/50 text-blue-200 hover:bg-blue-900/50' : 'bg-green-900/30 border-green-500/50 text-green-200 hover:bg-green-900/50'}`}
                >
                    {mode === 'fusion' ? <LayoutGrid size={14} /> : <ArrowRightLeft size={14} />}
                    <span className="text-xs font-medium">
                        {mode === 'fusion' ? '全域融合模式' : `域: ${currentDomain?.name || '未知'}`}
                    </span>
                    <ChevronDown size={12} className={`transition-transform ${isSwitcherOpen ? 'rotate-180' : ''}`} />
                </button>

                {isSwitcherOpen && (
                    <div className="absolute right-0 mt-2 w-80 bg-[#1e293b] border border-slate-700 rounded-lg shadow-2xl z-[100] overflow-hidden">
                        <div className="flex border-b border-slate-700">
                            <button 
                                onClick={() => setSwitcherTab('fusion')}
                                className={`flex-1 py-3 text-xs font-bold text-center transition-colors ${switcherTab === 'fusion' ? 'bg-blue-600/10 text-blue-400 border-b-2 border-blue-500' : 'text-slate-400 hover:text-slate-200 hover:bg-slate-800'}`}
                            >
                                跨域融合 (Fusion)
                            </button>
                            <button 
                                onClick={() => setSwitcherTab('switching')}
                                className={`flex-1 py-3 text-xs font-bold text-center transition-colors ${switcherTab === 'switching' ? 'bg-green-600/10 text-green-400 border-b-2 border-green-500' : 'text-slate-400 hover:text-slate-200 hover:bg-slate-800'}`}
                            >
                                域切换 (Switching)
                            </button>
                        </div>

                        <div className="p-4 max-h-[400px] overflow-y-auto custom-scrollbar bg-[#0f172a]">
                            {switcherTab === 'fusion' ? (
                                <div className="space-y-4">
                                    <div className="p-3 bg-blue-900/20 border border-blue-800 rounded text-blue-200 text-xs leading-relaxed">
                                        全局数据聚合：当前可查看所有域的组件与模板资源。
                                    </div>
                                    <button 
                                        onClick={handleSwitchToFusion}
                                        className="w-full py-2 bg-blue-600 hover:bg-blue-500 text-white rounded text-sm font-medium transition-colors flex items-center justify-center gap-2"
                                    >
                                        {mode === 'fusion' && <Check size={16} />}
                                        启用融合模式
                                    </button>
                                </div>
                            ) : (
                                <div className="space-y-3">
                                    {MOCK_DOMAINS.filter(d => !d.isSuper).map(domain => (
                                        <button
                                            key={domain.id}
                                            onClick={() => handleSwitchToDomain(domain)}
                                            className={`w-full flex items-center justify-between p-3 rounded border text-left transition-all ${
                                                mode === 'switching' && currentDomain?.id === domain.id
                                                ? 'bg-green-900/20 border-green-500/50 text-green-300'
                                                : 'bg-slate-800 border-slate-700 text-slate-300 hover:border-slate-500 hover:bg-slate-700'
                                            }`}
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className={`w-8 h-8 rounded-full flex items-center justify-center ${mode === 'switching' && currentDomain?.id === domain.id ? 'bg-green-900/40 text-green-400' : 'bg-slate-700 text-slate-400'}`}>
                                                    <Users size={14} />
                                                </div>
                                                <div className="truncate text-sm font-bold">{domain.name}</div>
                                            </div>
                                            {mode === 'switching' && currentDomain?.id === domain.id && <Check size={16} className="text-green-500" />}
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                )}
            </div>

            <div className="flex items-center space-x-3 pl-4 border-l border-slate-700">
                <div className="flex flex-col items-end">
                    <span className="text-sm font-medium text-white">{mode === 'fusion' ? '超级管理员' : (currentDomain?.manager)}</span>
                    <span className="text-[10px] text-slate-500">{mode === 'fusion' ? '省中心' : '项目域'}</span>
                </div>
                <div className="w-9 h-9 rounded-full bg-slate-800 border border-slate-600 flex items-center justify-center">
                    <UserIcon size={18} className="text-slate-300" />
                </div>
                <button className="text-slate-400 hover:text-red-400 transition-colors">
                    <LogOut size={18} />
                </button>
            </div>
         </div>
      </header>

      <main className="flex-1 overflow-hidden bg-[#020617] flex flex-col p-6">
        <div className="mb-4 flex items-center justify-between">
             <div className="flex items-center text-sm text-slate-400">
                <span>{breadcrumbs.parent}</span>
                <span className="mx-2 text-slate-600">/</span>
                <span className="text-blue-400 font-medium">{breadcrumbs.child}</span>
             </div>
             {mode === 'switching' && currentDomain && (
                 <div className="flex items-center px-3 py-1 bg-blue-900/20 border border-blue-500/30 rounded text-[10px] text-blue-400">
                    <Network size={12} className="mr-1"/> 
                    业务类型限制生效中
                 </div>
             )}
        </div>
        <div className="flex-1 overflow-hidden">
            {renderContent()}
        </div>
      </main>
    </div>
    </GlobalContext.Provider>
  );
};

