import React, { useState, useMemo, useEffect } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, Pagination, SectionTitle } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, Folder, ChevronDown, ChevronRight, Phone, Mail, User, Grid, RefreshCcw, Settings, Lock, Building2 } from 'lucide-react';
import { MOCK_DEPTS, MOCK_DOMAINS } from '../constants';
import { Department, Domain } from '../types';
import { useGlobalContext } from '../GlobalContext';

// Unified Node Type for the Sidebar
type MixedNode = {
    id: string;
    name: string;
    type: 'domain' | 'dept';
    data: Domain | Department;
    children?: MixedNode[];
};

export const DeptManager: React.FC = () => {
  const { mode, currentDomain } = useGlobalContext();

  // -- Selection State --
  const [selectedDomainId, setSelectedDomainId] = useState<string>('');
  const [expandedKeys, setExpandedKeys] = useState<Set<string>>(new Set());

  // -- Data State (Departments) --
  const [deptData, setDeptData] = useState<Department[]>(MOCK_DEPTS);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [expandedTableKeys, setExpandedTableKeys] = useState<Set<string>>(new Set(['1', '11', '12'])); // Default expand top level for existing mock

  // Search State
  const [searchName, setSearchName] = useState('');
  const [searchStatus, setSearchStatus] = useState('');

  // Edit/Add State
  const [currentDept, setCurrentDept] = useState<Partial<Department>>({});

  // Confirm Dialog State
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'inactive' } | null>(null);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  // --- Initialization ---
  useEffect(() => {
      // Set default selected domain
      if (mode === 'switching' && currentDomain) {
          setSelectedDomainId(currentDomain.id);
          setExpandedKeys(new Set([currentDomain.id]));
      } else {
          // Find root
          const root = MOCK_DOMAINS.find(d => !d.parentId);
          if (root) {
              setSelectedDomainId(root.id);
              setExpandedKeys(new Set([root.id]));
          }
      }
  }, [mode, currentDomain]);

  // --- Left Tree Logic (Mixed Domain + Depts) ---
  const mixedTree = useMemo(() => {
      // 1. Convert Domains to MixedNodes
      const domainNodes = new Map<string, MixedNode>();

      // Filter domains based on mode
      let visibleDomains = MOCK_DOMAINS;
      if (mode === 'switching' && currentDomain) {
          visibleDomains = [currentDomain];
      }

      visibleDomains.forEach(d => {
          domainNodes.set(d.id, {
              id: d.id,
              name: d.name,
              type: 'domain',
              data: d,
              children: []
          });
      });

      const rootNodes: MixedNode[] = [];

      // 2. Build Domain Hierarchy
      // In switching mode, there's typically only one root domain shown.
      // In fusion, relationships exist.
      visibleDomains.forEach(d => {
          const node = domainNodes.get(d.id)!;
          if (d.parentId && domainNodes.has(d.parentId)) {
              domainNodes.get(d.parentId)!.children!.push(node);
          } else {
              rootNodes.push(node);
          }
      });

      // 3. Attach Departments to Domains
      // Helper to recursively convert Department to MixedNode
      const convertDept = (d: Department): MixedNode => ({
          id: d.id,
          name: d.name,
          type: 'dept',
          data: d,
          children: d.children ? d.children.map(convertDept) : []
      });

      // deptData contains root-level departments per domain
      const attachDepts = (nodes: MixedNode[]) => {
          nodes.forEach(node => {
              if (node.type === 'domain') {
                  const domainId = node.id;
                  const roots = deptData.filter(d => d.domainId === domainId);
                  const deptNodes = roots.map(convertDept);
                  // Append departments to domain children (domains can contain sub-domains AND depts)
                  node.children = [...(node.children || []), ...deptNodes];
              }
              // Recurse into children (sub-domains or departments?)
              // Only domains can have mixed children here (sub-domains).
              // Departments only have sub-departments.
              if (node.children) {
                  attachDepts(node.children);
              }
          });
      };

      // Note: We only need to run attachDepts on the Domain nodes. The convertDept function handles Dept recursion.
      // The recursive attachDepts above is redundant if we only attach to domains.
      // Let's simplified: iterate all domain nodes and attach their depts.
      domainNodes.forEach((node) => {
          const roots = deptData.filter(d => d.domainId === node.id);
          const deptNodes = roots.map(convertDept);
          node.children = [...(node.children || []), ...deptNodes];
      });

      return rootNodes;
  }, [mode, currentDomain, deptData]);

  const toggleExpand = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      const newSet = new Set(expandedKeys);
      if (newSet.has(id)) newSet.delete(id);
      else newSet.add(id);
      setExpandedKeys(newSet);
  };

  const handleSidebarClick = (node: MixedNode) => {
      if (node.type === 'domain') {
          setSelectedDomainId(node.id);
      } else {
          // If clicking a department, select its domain context
          const domainId = (node.data as Department).domainId;
          setSelectedDomainId(domainId);
          // Optional: Could expand tree table to show this dept, but simple selection is fine for now
      }
  };

  const renderSidebarNodes = (nodes: MixedNode[], depth = 0) => {
      return nodes.map(node => {
          const isExpanded = expandedKeys.has(node.id);
          const isSelected = selectedDomainId === (node.type === 'domain' ? node.id : (node.data as Department).domainId) && node.type === 'domain'; 
          // Highlight logic: if domain selected, highlight domain node.
          // If we wanted to highlight dept, we'd need selectedDeptId state. Keeping it simple.

          const hasChildren = node.children && node.children.length > 0;

          return (
              <div key={node.id}>
                  <div 
                      className={`flex items-center py-2 px-2 cursor-pointer transition-all rounded-md mb-1 border border-transparent ${isSelected ? 'bg-blue-600 text-white shadow-md shadow-blue-900/20' : 'text-slate-300 hover:bg-slate-800 hover:border-slate-700'}`}
                      style={{ paddingLeft: `${depth * 16 + 8}px` }}
                      onClick={() => handleSidebarClick(node)}
                  >
                      <div 
                        className={`mr-1 p-0.5 rounded hover:bg-white/20 transition-colors ${hasChildren ? 'visible' : 'invisible'}`}
                        onClick={(e) => toggleExpand(e, node.id)}
                      >
                          {isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                      </div>

                      {node.type === 'domain' ? (
                          <Building2 size={14} className={`mr-2 ${isSelected ? 'text-white' : 'text-blue-500'}`} />
                      ) : (
                          <Folder size={14} className="mr-2 text-yellow-500" />
                      )}

                      <span className="text-sm truncate select-none font-medium">{node.name}</span>
                  </div>
                  {isExpanded && node.children && renderSidebarNodes(node.children, depth + 1)}
              </div>
          );
      });
  };

  // --- Right Content Logic (Department Tree Table) ---

  // 1. Filter Departments by Selected Domain
  const domainDepartments = useMemo(() => {
      return deptData.filter(d => d.domainId === selectedDomainId);
  }, [deptData, selectedDomainId]);

  // 2. Flatten for Table
  const flattenDepts = (depts: Department[], depth = 0): (Department & { depth: number })[] => {
    let result: (Department & { depth: number })[] = [];
    depts.forEach(d => {
      result.push({ ...d, depth });
      if (d.children && expandedTableKeys.has(d.id)) {
        result = result.concat(flattenDepts(d.children, depth + 1));
      }
    });
    return result;
  };

  // 3. Apply Search Filter
  const flatData = useMemo(() => {
      const visibleNodes = flattenDepts(domainDepartments);
      return visibleNodes.filter(d => {
          const matchName = !searchName || d.name.toLowerCase().includes(searchName.toLowerCase());
          const matchStatus = !searchStatus || d.status === searchStatus;
          return matchName && matchStatus;
      });
  }, [domainDepartments, expandedTableKeys, searchName, searchStatus]);

  // Helper to get all nodes for parent selection in Modal
  const getAllNodes = (depts: Department[]): Department[] => {
      let res: Department[] = [];
      depts.forEach(d => {
          res.push(d);
          if (d.children) res = res.concat(getAllNodes(d.children));
      });
      return res;
  };

  const toggleTableExpand = (id: string) => {
      const newSet = new Set(expandedTableKeys);
      if (newSet.has(id)) newSet.delete(id);
      else newSet.add(id);
      setExpandedTableKeys(newSet);
  };

  // --- Handlers ---

  const handleAdd = (parentId: string | null = null) => {
      if (!selectedDomainId) {
          alert("请先选择左侧组织机构(域)");
          return;
      }
      setCurrentDept({
          parentId,
          domainId: selectedDomainId,
          status: 'active',
          sort: 1
      });
      setIsModalOpen(true);
  };

  const handleEdit = (dept: Department) => {
      setCurrentDept({ ...dept });
      setIsModalOpen(true);
  };

  const handleSave = () => {
      if (!currentDept.name || !currentDept.leader) {
          alert("请完善基本信息");
          return;
      }

      const deptToSave = { ...currentDept } as Department;

      // Recursive update helper
      const updateInTree = (nodes: Department[]): Department[] => {
          return nodes.map(n => {
              if (n.id === currentDept.id) {
                  return { ...n, ...deptToSave, children: n.children }; 
              }
              if (n.children) {
                  return { ...n, children: updateInTree(n.children) };
              }
              return n;
          });
      };

      // Recursive add helper
      const addInTree = (nodes: Department[], newItem: Department): Department[] => {
          return nodes.map(n => {
              if (n.id === newItem.parentId) {
                  return { ...n, children: [...(n.children || []), newItem] };
              }
              if (n.children) {
                  return { ...n, children: addInTree(n.children, newItem) };
              }
              return n;
          });
      };

      if (currentDept.id) {
          // Update
          setDeptData(updateInTree(deptData));
      } else {
          // Create
          const newDept = {
              ...deptToSave,
              id: Date.now().toString(),
              createTime: new Date().toLocaleDateString(),
              children: []
          } as Department;

          if (newDept.parentId) {
              setDeptData(addInTree(deptData, newDept));
              // Auto expand parent in table
              setExpandedTableKeys(new Set([...expandedTableKeys, newDept.parentId]));
          } else {
              // Add as root for this domain
              setDeptData([...deptData, newDept]);
          }
      }
      setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          const removeNode = (nodes: Department[]): Department[] => {
              return nodes.filter(n => n.id !== deleteTargetId).map(n => ({
                  ...n,
                  children: n.children ? removeNode(n.children) : undefined
              }));
          };
          setDeptData(removeNode(deptData));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  const initiateStatusChange = (dept: Department, checked: boolean) => {
      setTargetStatusChange({ id: dept.id, newStatus: checked ? 'active' : 'inactive' });
      setConfirmOpen(true);
  };

  const confirmStatusChange = () => {
      if (targetStatusChange) {
          const updateStatus = (nodes: Department[]): Department[] => {
              return nodes.map(n => {
                  if (n.id === targetStatusChange.id) {
                      return { ...n, status: targetStatusChange.newStatus };
                  }
                  if (n.children) {
                      return { ...n, children: updateStatus(n.children) };
                  }
                  return n;
              });
          };
          setDeptData(updateStatus(deptData));
      }
      setConfirmOpen(false);
      setTargetStatusChange(null);
  };

  const columns = [
      {
          header: '部门名称',
          accessor: (row: any) => (
              <div style={{ paddingLeft: `${row.depth * 24}px` }} className="flex items-center">
                  {row.children && row.children.length > 0 ? (
                      <button onClick={() => toggleTableExpand(row.id)} className="mr-2 text-slate-400 hover:text-white">
                          {expandedTableKeys.has(row.id) ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                      </button>
                  ) : <span className="w-[22px]"></span>}
                  <Folder size={16} className="mr-2 text-blue-500" />
                  <span className="text-slate-200 font-medium">{row.name}</span>
              </div>
          ),
          width: '30%'
      },
      { header: '负责人', accessor: 'leader', width: '15%' },
      { header: '联系电话', accessor: 'phone', width: '15%' },
      { header: '排序', accessor: 'sort', width: '10%' },
      {
          header: '状态',
          accessor: (row: Department) => (
              <Switch 
                  checked={row.status === 'active'} 
                  onChange={(c) => initiateStatusChange(row, c)} 
              />
          ),
          width: '10%'
      },
      { header: '创建时间', accessor: 'createTime' },
      {
          header: '操作',
          accessor: (row: Department) => (
              <div className="flex space-x-2">
                  <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row)}>编辑</Button>
                  <Button size="sm" variant="ghost" className="!text-green-500 hover:!text-green-400" icon={<Plus size={14} />} onClick={() => handleAdd(row.id)}>新增下级</Button>
                  <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.id)}>删除</Button>
              </div>
          ),
          width: '250px'
      }
  ];

  const selectedDomainName = MOCK_DOMAINS.find(d => d.id === selectedDomainId)?.name || '未选择';

  return (
      <div className="h-full flex gap-4 overflow-hidden">
          {/* Left Sidebar: Mixed Tree */}
          <Card className="w-72 shrink-0 flex flex-col" title="组织机构">
              <div className="mb-3">
                  <Input placeholder="搜索组织/部门..." className="text-xs h-8" prefix={<Search size={14}/>} />
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar -mx-2 px-2">
                  {renderSidebarNodes(mixedTree)}
              </div>
          </Card>

          {/* Right Content */}
          <div className="flex-1 flex flex-col gap-4 overflow-hidden">
              <Card className="shrink-0">
                  <div className="flex justify-between items-end">
                      <div className="flex gap-4 items-end">
                          <Input 
                              label="部门名称"
                              placeholder="请输入部门名称"
                              className="w-48"
                              value={searchName}
                              onChange={e => setSearchName(e.target.value)}
                          />
                          <Select 
                              label="状态"
                              options={[{label: '全部', value: ''}, {label: '正常', value: 'active'}, {label: '停用', value: 'inactive'}]}
                              value={searchStatus}
                              onChange={e => setSearchStatus(e.target.value)}
                              className="w-32"
                          />
                          <div className="flex gap-2 pb-0.5">
                              <Button icon={<Search size={16}/>}>查询</Button>
                              <Button variant="secondary" icon={<RotateCcw size={16}/>} onClick={() => { setSearchName(''); setSearchStatus(''); }}>重置</Button>
                          </div>
                      </div>
                  </div>
              </Card>

              <Card className="flex-1 overflow-hidden flex flex-col">
                  {/* Toolbar */}
                  <div className="flex justify-between items-center mb-4">
                       <div className="flex gap-2 items-center">
                           <Button variant="primary" className="bg-blue-600 hover:bg-blue-500" icon={<Plus size={16} />} onClick={() => handleAdd()}>新增部门</Button>
                           <span className="text-xs text-slate-500 ml-2">当前归属域: <span className="text-blue-400 font-medium">{selectedDomainName}</span></span>
                       </div>
                       <div className="flex gap-2">
                           <button className="p-2 text-slate-400 hover:bg-slate-800 rounded transition-colors" title="刷新"><RefreshCcw size={16}/></button>
                           <button className="p-2 text-slate-400 hover:bg-slate-800 rounded transition-colors" title="密度"><Grid size={16}/></button>
                           <button className="p-2 text-slate-400 hover:bg-slate-800 rounded transition-colors" title="设置"><Settings size={16}/></button>
                       </div>
                  </div>

                  <div className="flex-1 overflow-auto">
                      <Table columns={columns} data={flatData} keyField="id" />
                  </div>
              </Card>
          </div>

          {/* Add/Edit Modal */}
          <Modal
              isOpen={isModalOpen}
              onClose={() => setIsModalOpen(false)}
              title={currentDept.id ? "编辑部门" : "新增部门"}
              size="md"
              footer={
                  <>
                      <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
                      <Button onClick={handleSave}>确定</Button>
                  </>
              }
          >
              <div className="space-y-6">
                  <SectionTitle title="部门信息" />
                  <div className="space-y-4">
                      {/* Domain Read-only Field */}
                      <div className="relative">
                           <label className="text-sm text-slate-400 block mb-1.5">归属组织 (Domain)</label>
                           <Select 
                              options={MOCK_DOMAINS.map(d => ({ label: d.name, value: d.id }))}
                              value={currentDept.domainId}
                              disabled={true}
                              className="opacity-60 cursor-not-allowed bg-slate-800"
                           />
                           <div className="absolute right-8 top-9 text-slate-500 pointer-events-none flex items-center gap-1">
                              <Lock size={12} />
                              <span className="text-xs">锁定</span>
                           </div>
                      </div>

                      <div className="relative">
                          <label className="text-sm text-slate-400 block mb-1.5">上级部门</label>
                          <select 
                              className="w-full px-3 py-2 bg-[#1e293b] border border-slate-700 rounded focus:ring-1 focus:ring-blue-500 focus:border-blue-500 text-white appearance-none hover:border-slate-600"
                              value={currentDept.parentId || ''}
                              onChange={e => setCurrentDept({...currentDept, parentId: e.target.value || null})}
                          >
                              <option value="">顶级部门</option>
                              {getAllNodes(domainDepartments).map(d => (
                                  <option key={d.id} value={d.id} disabled={d.id === currentDept.id}>{d.name}</option>
                              ))}
                          </select>
                          <ChevronDown size={14} className="absolute right-3 top-[38px] pointer-events-none text-slate-500" />
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                          <Input 
                              label="部门名称"
                              placeholder="请输入"
                              value={currentDept.name || ''}
                              onChange={e => setCurrentDept({...currentDept, name: e.target.value})}
                          />
                          <Input 
                              label="显示排序"
                              type="number"
                              value={currentDept.sort || 0}
                              onChange={e => setCurrentDept({...currentDept, sort: parseInt(e.target.value)})}
                          />
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                          <Input 
                              label="负责人"
                              placeholder="负责人姓名"
                              value={currentDept.leader || ''}
                              onChange={e => setCurrentDept({...currentDept, leader: e.target.value})}
                              prefix={<User size={14}/>}
                          />
                          <Input 
                              label="联系电话"
                              placeholder="手机号码"
                              value={currentDept.phone || ''}
                              onChange={e => setCurrentDept({...currentDept, phone: e.target.value})}
                              prefix={<Phone size={14}/>}
                          />
                      </div>

                      <Input 
                          label="邮箱"
                          placeholder="部门邮箱"
                          value={currentDept.email || ''}
                          onChange={e => setCurrentDept({...currentDept, email: e.target.value})}
                          prefix={<Mail size={14}/>}
                      />

                      <div className="flex flex-col gap-2">
                          <label className="text-sm text-slate-400">部门状态</label>
                          <div className="flex items-center gap-2">
                              <Switch 
                                  checked={currentDept.status === 'active'}
                                  onChange={c => setCurrentDept({...currentDept, status: c ? 'active' : 'inactive'})}
                              />
                              <span className="text-sm text-slate-300">{currentDept.status === 'active' ? '正常' : '停用'}</span>
                          </div>
                      </div>
                  </div>
              </div>
          </Modal>

          <ConfirmDialog 
              isOpen={confirmOpen} 
              message={`确定要${targetStatusChange?.newStatus === 'active' ? '启用' : '停用'}该部门吗？`}
              onConfirm={confirmStatusChange}
              onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
          />

          <ConfirmDialog 
              isOpen={deleteConfirmOpen} 
              title="删除部门"
              message="确定要删除该部门吗？如果有下级部门将一并删除。"
              onConfirm={confirmDelete}
              onCancel={() => { setDeleteConfirmOpen(false); setDeleteTargetId(null); }}
          />
      </div>
  );
};

import React, { ReactNode, useState, useRef, useEffect } from 'react';
import { X, Check, AlertCircle, ChevronDown, Search, ChevronLeft, ChevronRight } from 'lucide-react';

// --- Colors ---
// Using Tailwind standard palette, keeping in mind the dark blue enterprise theme.
// Primary: blue-600
// Bg: slate-900 / slate-800
// Border: slate-700

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  icon?: ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ variant = 'primary', size = 'md', icon, children, className, ...props }) => {
  const baseStyle = "inline-flex items-center justify-center rounded transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-blue-600 hover:bg-blue-500 text-white focus:ring-blue-500 shadow-sm",
    secondary: "bg-slate-800 hover:bg-slate-700 text-slate-200 focus:ring-slate-500 border border-slate-600",
    danger: "bg-red-600 hover:bg-red-500 text-white focus:ring-red-500",
    ghost: "bg-transparent hover:bg-slate-800 text-slate-300 hover:text-white"
  };

  const sizes = {
    sm: "px-2 py-1 text-xs",
    md: "px-4 py-1.5 text-sm", // Adjusted height slightly
    lg: "px-6 py-3 text-base"
  };

  return (
    <button className={`${baseStyle} ${variants[variant]} ${sizes[size]} ${className || ''}`} {...props}>
      {icon && <span className="mr-2">{icon}</span>}
      {children}
    </button>
  );
};

export const Switch: React.FC<{ checked: boolean; onChange: (checked: boolean) => void; disabled?: boolean }> = ({ checked, onChange, disabled }) => {
  return (
    <button 
      type="button"
      role="switch"
      aria-checked={checked}
      onClick={() => !disabled && onChange(!checked)}
      className={`relative inline-flex h-5 w-9 flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 focus:ring-offset-slate-900 ${checked ? 'bg-emerald-500' : 'bg-red-500'} ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
    >
      <span className="sr-only">Use setting</span>
      <span
        aria-hidden="true"
        className={`pointer-events-none inline-block h-4 w-4 transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out ${checked ? 'translate-x-4' : 'translate-x-0'}`}
      />
    </button>
  );
};

export const Card: React.FC<{ children: ReactNode; title?: string; className?: string; action?: ReactNode }> = ({ children, title, className, action }) => (
  <div className={`bg-slate-800/40 border border-slate-700/50 rounded-lg shadow-sm backdrop-blur-sm ${className || ''}`}>
    {title && (
      <div className="px-5 py-3 border-b border-slate-700/50 flex justify-between items-center bg-slate-900/30 rounded-t-lg">
        <h3 className="font-semibold text-slate-100 flex items-center gap-2">
           <div className="w-1 h-4 bg-blue-500 rounded-full"></div>
           {title}
        </h3>
        {action && <div>{action}</div>}
      </div>
