interface TableProps {
  columns: { header: string; accessor: string | ((row: any) => ReactNode); width?: string }[];
  data: any[];
  keyField?: string;
}

export const Table: React.FC<TableProps> = ({ columns, data, keyField = 'id' }) => {
  return (
    <div className="overflow-hidden border border-slate-700/50 rounded-lg shadow-sm">
      <table className="min-w-full divide-y divide-slate-800 bg-[#0f172a]">
        <thead className="bg-slate-900">
          <tr>
            {columns.map((col, idx) => (
              <th key={idx} className="px-6 py-3.5 text-left text-xs font-semibold text-slate-400 uppercase tracking-wider" style={{ width: col.width }}>
                {col.header}
              </th>
            ))}
          </tr>
